CREATE OR REPLACE FUNCTION fpa_tel_get_shr_state_real (as_memno char,adt_bdate timestamp(0),adt_edate timestamp(0)) RETURNS bigint AS $body$
DECLARE

  ldc_return bigint;

BEGIN
  select  sum(sc_mem_m_share_holding_detail.share_stock * sc_mem_m_ucf_share_item_type.sign_flag)
  into STRICT    ldc_return
  from    sc_mem_m_share_holding_detail
        , sc_mem_m_ucf_share_item_type
  where (sc_mem_m_ucf_share_item_type.item_type = sc_mem_m_share_holding_detail.item_type )
  and (sc_mem_m_share_holding_detail.membership_no = as_memno)
  and (sc_mem_m_share_holding_detail.operate_date between adt_bdate and adt_edate);

return   ldc_return;

exception when others then CALL spa_dberror('FPA_TEL_GET_SHR_STATE_REAL');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
